    /// Synchronous generation — runs on a blocking thread.
    fn generate_sync(
        model: &LlamaModel,
        messages: &[(String, String)],
        temperature: f32,
        max_tokens: u32,
    ) -> Result<GenerateResult, Status> {
        use llama_cpp_2::context::params::LlamaContextParams;
